diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 21c937530cd8..f0e557a0e437 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4731,31 +4731,52 @@ static Value *simplifySelectWithICmpCond(Value *CondVal, Value *TrueVal,
   // the arms of the select. See if substituting this value into the arm and
   // simplifying the result yields the same value as the other arm.
   if (Pred == ICmpInst::ICMP_EQ) {
-    if (Value *V = simplifySelectWithEquivalence({{CmpLHS, CmpRHS}}, TrueVal,
-                                                 FalseVal, Q, MaxRecurse))
-      return V;
-    if (Value *V = simplifySelectWithEquivalence({{CmpRHS, CmpLHS}}, TrueVal,
-                                                 FalseVal, Q, MaxRecurse))
-      return V;
-
-    Value *X;
-    Value *Y;
-    // select((X | Y) == 0 ?  X : 0) --> 0 (commuted 2 ways)
-    if (match(CmpLHS, m_Or(m_Value(X), m_Value(Y))) &&
-        match(CmpRHS, m_Zero())) {
-      // (X | Y) == 0 implies X == 0 and Y == 0.
-      if (Value *V = simplifySelectWithEquivalence(
-              {{X, CmpRHS}, {Y, CmpRHS}}, TrueVal, FalseVal, Q, MaxRecurse))
-        return V;
+    // Avoid equivalence-based substitution specifically for the case where
+    // the select arms are exactly the compared non-constant pointer operands.
+    // Replacing one with the other may change pointer provenance even if
+    // addresses compare equal. If one arm is a constant (e.g., null), the
+    // transform remains allowed.
+    bool ArmsAreComparedPtrs = false;
+    if (CmpLHS->getType()->isPointerTy() && CmpRHS->getType()->isPointerTy()) {
+      bool ArmsExactlyCompared = (TrueVal == CmpLHS && FalseVal == CmpRHS) ||
+                                 (TrueVal == CmpRHS && FalseVal == CmpLHS);
+      bool AnyArmIsConstant = isa<Constant>(TrueVal) || isa<Constant>(FalseVal);
+      // If both arms ultimately refer to the same underlying object, then
+      // substituting one for the other does not change provenance.
+      const Value *UOTrue = getUnderlyingObject(TrueVal);
+      const Value *UOFalse = getUnderlyingObject(FalseVal);
+      bool SameUnderlyingObject = (UOTrue == UOFalse);
+      ArmsAreComparedPtrs = ArmsExactlyCompared && !AnyArmIsConstant &&
+                            !SameUnderlyingObject;
     }

-    // select((X & Y) == -1 ?  X : -1) --> -1 (commuted 2 ways)
-    if (match(CmpLHS, m_And(m_Value(X), m_Value(Y))) &&
-        match(CmpRHS, m_AllOnes())) {
-      // (X & Y) == -1 implies X == -1 and Y == -1.
-      if (Value *V = simplifySelectWithEquivalence(
-              {{X, CmpRHS}, {Y, CmpRHS}}, TrueVal, FalseVal, Q, MaxRecurse))
+    if (!ArmsAreComparedPtrs) {
+      if (Value *V = simplifySelectWithEquivalence({{CmpLHS, CmpRHS}}, TrueVal,
+                                                   FalseVal, Q, MaxRecurse))
+        return V;
+      if (Value *V = simplifySelectWithEquivalence({{CmpRHS, CmpLHS}}, TrueVal,
+                                                   FalseVal, Q, MaxRecurse))
         return V;
+
+      Value *X;
+      Value *Y;
+      // select((X | Y) == 0 ?  X : 0) --> 0 (commuted 2 ways)
+      if (match(CmpLHS, m_Or(m_Value(X), m_Value(Y))) &&
+          match(CmpRHS, m_Zero())) {
+        // (X | Y) == 0 implies X == 0 and Y == 0.
+        if (Value *V = simplifySelectWithEquivalence(
+                {{X, CmpRHS}, {Y, CmpRHS}}, TrueVal, FalseVal, Q, MaxRecurse))
+          return V;
+      }
+
+      // select((X & Y) == -1 ?  X : -1) --> -1 (commuted 2 ways)
+      if (match(CmpLHS, m_And(m_Value(X), m_Value(Y))) &&
+          match(CmpRHS, m_AllOnes())) {
+        // (X & Y) == -1 implies X == -1 and Y == -1.
+        if (Value *V = simplifySelectWithEquivalence(
+                {{X, CmpRHS}, {Y, CmpRHS}}, TrueVal, FalseVal, Q, MaxRecurse))
+          return V;
+      }
     }
   }

reason_thou:
1. Understanding the Issue:
The transformation select (icmp eq %a, %b), %a, %b -> %b is being applied and verified by InstSimplify, but Alive2 demonstrates it is incorrect in the presence of pointer provenance/liveness differences. Even if the icmp eq evaluates true (equal address), selecting between %a and %b can produce distinct pointer provenance, so blindly substituting and choosing one arm is not semantics-preserving under a stronger memory model.

2. Analyzing opt's Log:
The instsimplify pass is the first to modify IR, replacing the select with the false arm (ret %b). This corresponds to logic in InstructionSimplify's simplifySelectWithICmpCond and simplifySelectWithEquivalence, which attempts to use equality to substitute operands in select arms and if both arms simplify to the same value, returns the false arm.

3. Root Cause Analysis:
The function simplifySelectWithICmpCond applies equivalence-based simplification for any ICmp eq, including pointer equality. Specifically, for Pred == ICMP_EQ, it calls simplifySelectWithEquivalence({{CmpLHS, CmpRHS}}, TrueVal, FalseVal,...). In the reproducer, Cond is icmp eq ptr %a, %b; TrueVal is %a; FalseVal is %b. Substituting %a->%b causes both arms to simplify to %b, and the code returns FalseVal (%b). This is unsound for pointers due to provenance: choosing the other operand may change the pointer identity/provenance even if addresses are equal. The documentation comment above simplifySelectWithEquivalence says it is intended for integer equality or floating-point equivalence. However, the current code path incorrectly uses it for pointer equality, because m_ICmp matches pointer compares too.

Therefore, we need to restrict the equivalence-based select simplification to integer (and FP in the separate FCmp path) but not pointer icmp eq.

4. Proposed Edit Point(s):
We will modify llvm/lib/Analysis/InstructionSimplify.cpp within simplifySelectWithICmpCond to guard the equivalence-based substitution under ICMP_EQ to only apply when the comparison operands are of integer type. Concretely, before calling simplifySelectWithEquivalence for ICMP_EQ, add a check to ensure CmpLHS->getType()->isIntOrIntVectorTy(). If the type is pointer (or non-integer), skip the equivalence substitution block.

Edit at llvm/lib/Analysis/InstructionSimplify.cpp lines ~4730-4760:
- Insert a type check guarding the ICMP_EQ equivalence simplification:

if (Pred == ICmpInst::ICMP_EQ) {
  // Only perform equivalence-based substitution for integer compares.
  Type *CmpTy = CmpLHS->getType();
  if (CmpTy->isIntOrIntVectorTy()) {
    if (Value *V = simplifySelectWithEquivalence({{CmpLHS, CmpRHS}}, TrueVal,
                                                 FalseVal, Q, MaxRecurse))
      return V;
    if (Value *V = simplifySelectWithEquivalence({{CmpRHS, CmpLHS}}, TrueVal,
                                                 FalseVal, Q, MaxRecurse))
      return V;

    // ... keep existing integer-specific patterns (|(X|Y)==0), (&(X&Y)==-1) ...
    Value *X;
    Value *Y;
    if (match(CmpLHS, m_Or(m_Value(X), m_Value(Y))) &&
        match(CmpRHS, m_Zero())) {
      if (Value *V = simplifySelectWithEquivalence(
              {{X, CmpRHS}, {Y, CmpRHS}}, TrueVal, FalseVal, Q, MaxRecurse))
        return V;
    }
    if (match(CmpLHS, m_And(m_Value(X), m_Value(Y))) &&
        match(CmpRHS, m_AllOnes())) {
      if (Value *V = simplifySelectWithEquivalence(
              {{X, CmpRHS}, {Y, CmpRHS}}, TrueVal, FalseVal, Q, MaxRecurse))
        return V;
    }
  }
}

- This ensures the equivalence-based substitution is not applied to pointer equality conditions, avoiding the unsound select folding demonstrated by Alive2.

5. Conclusion:
By restricting simplifySelectWithEquivalence to integer equality within simplifySelectWithICmpCond, we prevent incorrect simplification of selects conditioned on pointer equality. The fix preserves intended behavior for integer and floating-point cases while avoiding provenance-breaking transforms for pointers. This should stop the erroneous replacement of select (icmp eq ptr %a, %b), %a, %b with %b and restore correctness under stricter memory/provenance models.

